// 按层遍历的写法
queue<int> q;
q.push(start);
vis[start] = true;
int step = 0;

while (!q.empty()) {
  int sz = q.size();      // 当前层的节点数
  for (int i = 0; i < sz; i++) {
    int cur = q.front();
    q.pop();
    // 处理 cur ...
    for (int nxt : neighbors[cur]) {
      if (!vis[nxt]) {
        vis[nxt] = true;
        q.push(nxt);
      }
    }
  }
  step++;  // 一层结束了，步数 +1
}

